  // Handle: (icmp ne X, C) & (icmp ule (add X, -C), Y) --> icmp ult (add X, -C-1), Y
  // This pattern checks that X != C and X - C <= Y.
  // When X != C, X - C doesn't wrap, so X - C <= Y is equivalent to X < Y + C + 1.
  // Simplifying: X - C <= Y  -->  X < Y + C + 1  -->  X + (-C-1) < Y
  // Special case: C = -1, then -C-1 = 0, so X < Y.
  if (IsAnd) {
    Value *X, *Y;
    const APInt *C;
    ICmpInst::Predicate EqPred2, UnsignedPred;
    if (match(ZeroICmp, m_ICmp(EqPred2, m_Value(X), m_APInt(C))) &&
        ICmpInst::isEquality(EqPred2) && EqPred2 == ICmpInst::ICMP_NE &&
        match(UnsignedICmp,
              m_c_ICmp(UnsignedPred, m_c_Add(m_Specific(X), m_APInt(C)), m_Value(Y))) &&
        UnsignedPred == ICmpInst::ICMP_ULE &&
        (ZeroICmp->hasOneUse() || UnsignedICmp->hasOneUse())) {
      APInt NewC = -(*C) - 1;
      if (NewC == 0)
        return Builder.CreateICmpULT(X, Y);
      return Builder.CreateICmpULT(Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewC)), Y);
